from typing import List
from math import gcd
from functools import reduce

class Solution:
    def findKthSmallest(self, coins: List[int], k: int) -> int:
        def lcm(a, b):
            return a * b // gcd(a, b)

        def lcm_multiple(arr):
            return reduce(lcm, arr)

        def count_multiples(x):
            total = 0
            n = len(coins)
            for i in range(n):
                total += x // coins[i]
            for i in range(n):
                for j in range(i + 1, n):
                    total -= x // lcm(coins[i], coins[j])
            for i in range(n):
                for j in range(i + 1, n):
                    for k in range(j + 1, n):
                        total += x // lcm(lcm(coins[i], coins[j]), coins[k])
            return total

        left = 1
        right = 10**18  # A sufficiently large upper bound

        while left < right:
            mid = (left + right) // 2
            cnt = count_multiples(mid)
            if cnt < k:
                left = mid + 1
            else:
                right = mid

        return left
